{
  "steps": [
    {
      "text": "Open a web browser and go to `git-scm.com/downloads`. Keep this page open until you finish the installation.",
      "title": "Open the Git downloads page"
    },
    {
      "text": "Click the download link for your operating system: Windows, macOS, or Linux. The correct installer or install instructions should appear.",
      "title": "Choose your operating system"
    },
    {
      "text": "Open the downloaded Git installer. If your browser asks what to do with the file, choose **Open** or double-click it in your Downloads folder.",
      "title": "Run the Git installer"
    },
    {
      "text": "Click through the installer using its default options. Choose **Install** when it appears, then wait for the progress bar to finish.",
      "title": "Install Git with default options"
    },
    {
      "text": "Click **Finish** or **Close** when the installer reports completion. Git is now installed; leave any optional release-notes box unchecked unless you want to read it.",
      "title": "Finish the installation"
    },
    {
      "text": "Open a command-line app: Git Bash on Windows, Terminal on macOS, or your terminal app on Linux. You should see a prompt where you can type commands.",
      "title": "Open a terminal"
    },
    {
      "text": "Type `git --version` and press Enter. A successful installation displays a version such as `git version 2.45.0`.",
      "title": "Check the Git version"
    }
  ]
}

{
  "steps": [
    {
      "text": "Pull onto firm, level ground away from traffic. Turn on hazard lights, shift to Park (or first gear), set the parking brake, and keep passengers clear of the roadway.",
      "title": "Secure the vehicle"
    },
    {
      "text": "Place wheel chocks behind the wheels opposite the flat. If the front tire is flat, chock a rear wheel; if the rear tire is flat, chock a front wheel.",
      "title": "Chock the opposite wheels"
    },
    {
      "text": "Take out the spare tire, jack, lug wrench, and your owner’s manual. Find the manual’s diagram for the approved jack point nearest the flat tire.",
      "title": "Gather tools and find the jack point"
    },
    {
      "text": "Remove the hubcap or wheel cover if it hides the lug nuts. Use the flat end of the lug wrench or the tool supplied with the vehicle; the lug nuts should be fully visible.",
      "title": "Expose the lug nuts"
    },
    {
      "text": "Fit the lug wrench firmly over one lug nut. Turn it counterclockwise about one-quarter to one-half turn, then repeat for every lug nut. Do not remove them while the tire is on the ground.",
      "title": "Loosen the lug nuts"
    },
    {
      "text": "Position the jack directly under the approved jack point. Keep its base flat on solid ground; never place it under a plastic trim panel or an unapproved part of the vehicle.",
      "title": "Place the jack correctly"
    },
    {
      "text": "Raise the vehicle with the jack handle until the flat tire is about 2 inches off the ground. Stop if the jack tilts, sinks, or shifts; lower the vehicle and reposition it.",
      "title": "Lift the flat tire"
    },
    {
      "text": "Turn each loosened lug nut counterclockwise by hand and set it somewhere clean. Remove the nuts one at a time until the wheel is free.",
      "title": "Remove the lug nuts"
    },
    {
      "text": "Grip the tire at the 3 and 9 o’clock positions and pull it straight toward you. Set the flat tire flat on the ground, not upright, so it cannot roll away.",
      "title": "Remove the flat tire"
    },
    {
      "text": "Keep hands and feet out from under the raised vehicle. The wheel studs and empty hub should be exposed, confirming the flat tire has been safely removed.",
      "title": "Confirm safe removal"
    }
  ]
}

{
  "steps": [
    {
      "text": "Place a clean French press, a kettle, coffee beans or grounds, a grinder, a scale, a timer, and a mug on your counter.",
      "title": "Gather your equipment"
    },
    {
      "text": "Heat fresh water in the kettle to about 200°F. If you do not have a thermometer, bring it to a boil, then let it sit for 30 seconds.",
      "title": "Heat the water"
    },
    {
      "text": "Measure 30 grams of coffee beans on the scale. Use a medium-coarse grind; the particles should resemble coarse sea salt.",
      "title": "Measure and grind coffee"
    },
    {
      "text": "Add the 30 grams of ground coffee to the empty French press. The grounds should rest evenly at the bottom.",
      "title": "Add grounds to the press"
    },
    {
      "text": "Start your timer and pour 500 grams of hot water over the grounds. Make sure all grounds are wet and the water level stays below the rim.",
      "title": "Pour in hot water"
    },
    {
      "text": "Stir the coffee and water gently with a spoon or wooden stirrer. Break up any dry clumps floating on the surface.",
      "title": "Stir the coffee"
    },
    {
      "text": "Place the lid on the French press with the plunger pulled all the way up. Let the coffee steep undisturbed until the timer reaches 4 minutes.",
      "title": "Steep for four minutes"
    },
    {
      "text": "Press the plunger down slowly and steadily until the filter reaches the bottom. Stop if you feel strong resistance; lift slightly, then continue gently.",
      "title": "Plunge the press"
    },
    {
      "text": "Pour the brewed coffee into your mug immediately. The cup should look clear, with minimal loose grounds, and be ready to drink.",
      "title": "Pour and serve"
    }
  ]
}

{
  "steps": [
    {
      "text": "Choose a bed that receives at least 6–8 hours of direct sun. Remove any weeds, grass, stones, and old plant debris until the soil surface is clear.",
      "title": "Clear the garden bed"
    },
    {
      "text": "Push a garden fork 8–12 inches into the soil and lift gently to crack compacted areas. Work across the whole bed without turning the soil into fine dust.",
      "title": "Loosen the soil"
    },
    {
      "text": "Spread a 2–3 inch layer of finished compost evenly over the loosened bed. The compost should look dark and crumbly and smell earthy, not sour.",
      "title": "Add finished compost"
    },
    {
      "text": "Mix the compost into the top 6–8 inches of soil with a fork or shovel. Stop when the soil color and texture look consistent throughout the worked layer.",
      "title": "Blend in the compost"
    },
    {
      "text": "Squeeze a handful of moist soil. Add organic matter if it forms a hard lump; add a little water if it falls apart like dry powder. It should hold briefly, then crumble.",
      "title": "Check soil moisture and texture"
    },
    {
      "text": "Rake the bed level, breaking up only large clods and removing newly exposed stones. Leave a smooth, even surface with no standing water or deep depressions.",
      "title": "Level the planting bed"
    },
    {
      "text": "Wait until the soil is moist but not muddy before planting. Press a finger into the bed; it should enter easily and come out with crumbly soil, not sticky mud.",
      "title": "Confirm the bed is ready"
    }
  ]
}

{
  "steps": [
    {
      "text": "Clear a large, flat surface and gather your fabric, pillowcase pattern, measuring tape or ruler, fabric scissors or rotary cutter, pins, marking tool, and cutting mat if using a rotary cutter.",
      "title": "Prepare your cutting area"
    },
    {
      "text": "Press the fabric with an iron until it lies flat and wrinkle-free. Let it cool before measuring; the surface should not have folds or ripples.",
      "title": "Press the fabric flat"
    },
    {
      "text": "Find the fabric’s lengthwise edge, called the selvage. It is the tightly woven edge, often with printed dots or text, and should not fray.",
      "title": "Locate the selvage edges"
    },
    {
      "text": "Fold the fabric so the two selvage edges meet evenly. Smooth from the fold outward until both layers lie flat without shifting.",
      "title": "Fold fabric selvage to selvage"
    },
    {
      "text": "Place the pattern piece on the folded fabric as indicated by its printed layout. Align any “place on fold” line exactly along the fabric fold.",
      "title": "Position the pattern piece"
    },
    {
      "text": "Measure from the pattern’s grainline arrow to the selvage edge at both arrow ends. Shift the pattern until both measurements match.",
      "title": "Align the grainline"
    },
    {
      "text": "Insert pins through the pattern and both fabric layers, placing them inside the cutting line. Keep pins about 4 to 6 inches apart so the paper stays flat.",
      "title": "Pin the pattern securely"
    },
    {
      "text": "Trace around the pattern’s cutting line with a fabric marking tool if your pattern directs you to mark it. Include notches, dots, and fold marks.",
      "title": "Mark the pattern details"
    },
    {
      "text": "Cut slowly along the pattern’s outer cutting line with fabric scissors. Keep the fabric flat and lift only the scissors, not the fabric layers.",
      "title": "Cut around the pattern"
    },
    {
      "text": "Cut small outward notches at each marked notch, stopping before the seam allowance. Each notch should be less than 1/4 inch deep.",
      "title": "Clip the marked notches"
    },
    {
      "text": "Remove the pins and lift away the paper pattern. Keep each cut fabric piece flat; its edges should match the pattern shape and marked details.",
      "title": "Check the cut pieces"
    }
  ]
}

{
  "steps": [
    {
      "text": "Place your guitar where you can reach all six tuning pegs. Open a clip-on, pedal, or phone tuner, or prepare a reference-pitch source. The tuner should be powered on and ready to detect sound.",
      "title": "Prepare your tuner"
    },
    {
      "text": "Start with the thickest string, the low E. Pluck it once with a clear, moderate stroke and watch the tuner display. You should see a note letter and a needle or color indicator.",
      "title": "Pluck the low E string"
    },
    {
      "text": "Turn the low E tuning peg in tiny increments while repeatedly plucking the string. Stop when the tuner reads `E` and shows centered or green. If the pitch rises too far, loosen it and approach E again.",
      "title": "Tune the low E to E"
    },
    {
      "text": "Pluck the next-thickest string, the A string. Turn its tuning peg a little at a time until the tuner reads `A` and the indicator is centered or green.",
      "title": "Tune the A string to A"
    },
    {
      "text": "Pluck the D string, the third-thickest string. Adjust its tuning peg in small turns until the tuner displays `D` as in tune.",
      "title": "Tune the D string to D"
    },
    {
      "text": "Pluck the G string, the third-thinnest string. Adjust its peg slowly until the tuner reads `G` and indicates that the pitch is centered.",
      "title": "Tune the G string to G"
    },
    {
      "text": "Pluck the B string, the second-thinnest string. Make small peg adjustments until the tuner shows `B` and the in-tune indicator is centered or green.",
      "title": "Tune the B string to B"
    },
    {
      "text": "Pluck the thinnest string, the high E. Turn its peg carefully until the tuner reads `E` and marks it in tune. This E sounds much higher than the low E.",
      "title": "Tune the high E to E"
    },
    {
      "text": "Pluck each open string once from thickest to thinnest: `E A D G B E`. Retune any string that is no longer centered; changing tension on one string can slightly affect the others.",
      "title": "Recheck every string"
    }
  ]
}

{
  "steps": [
    {
      "text": "Turn on your camera and set the mode dial to `M` for Manual. You should see separate ISO, aperture, and shutter-speed values on the screen or top display.",
      "title": "Switch to Manual mode"
    },
    {
      "text": "Point the camera at the scene and half-press the shutter button. Find the exposure meter; it usually runs from negative to positive with `0` in the center.",
      "title": "Read the exposure meter"
    },
    {
      "text": "Set ISO to the lowest value that suits the available light, such as `ISO 100` outdoors in daylight. Confirm the ISO value changes on the display.",
      "title": "Choose a starting ISO"
    },
    {
      "text": "Rotate the aperture control to select an f-number for your image. Choose a small f-number such as `f/2.8` for blurrier backgrounds, or `f/8` for more scene sharpness.",
      "title": "Set the aperture"
    },
    {
      "text": "Rotate the shutter-speed control until the exposure meter moves near `0`. Use at least `1/125` for handheld subjects, or choose a faster speed for motion.",
      "title": "Set the shutter speed"
    },
    {
      "text": "Take a test photo using the shutter button. Review it on the camera screen; details should remain visible in both bright and dark areas.",
      "title": "Take a test photo"
    },
    {
      "text": "Lower the ISO, use a faster shutter speed, or select a higher f-number if highlights look washed out. Take another test photo after making the adjustment.",
      "title": "Correct an overly bright photo"
    },
    {
      "text": "Raise the ISO, use a slower shutter speed, or select a lower f-number if shadows are too dark. Hold the camera steady when using slower shutter speeds.",
      "title": "Correct an overly dark photo"
    },
    {
      "text": "Review the final image and histogram, if available. Keep the graph away from hard clipping at either edge, then retain the settings that give your intended brightness.",
      "title": "Confirm proper exposure"
    }
  ]
}

{
  "steps": [
    {
      "text": "Stand on a flat surface with enough clear space to move. Wear stable shoes or go barefoot if the surface is safe and non-slip.",
      "title": "Clear your exercise space"
    },
    {
      "text": "Place your feet about shoulder-width apart. Turn your toes slightly outward, in the same direction your knees will track.",
      "title": "Set your foot position"
    },
    {
      "text": "Press your whole foot into the floor, keeping your heels, big toes, and little toes grounded. You should feel balanced without gripping your toes.",
      "title": "Ground your feet"
    },
    {
      "text": "Lift your chest and keep your spine neutral. Look straight ahead or slightly downward; avoid arching your lower back or rounding your shoulders.",
      "title": "Align your torso"
    },
    {
      "text": "Extend both arms straight forward at shoulder height, or clasp your hands in front of your chest. Keep your arms still as you move.",
      "title": "Set your arm position"
    },
    {
      "text": "Breathe in, then push your hips back as if reaching for a chair behind you. Keep your chest lifted as your knees begin to bend.",
      "title": "Start the descent"
    },
    {
      "text": "Bend your knees and lower under control. Track each knee over the middle toes; do not let your knees collapse inward.",
      "title": "Track your knees"
    },
    {
      "text": "Lower until your thighs are parallel to the floor, or stop at the deepest position you can hold with heels down and a neutral spine.",
      "title": "Reach a controlled depth"
    },
    {
      "text": "Pause briefly at the bottom. Confirm that your heels stay down, knees follow your toes, chest stays lifted, and weight remains balanced over your whole feet.",
      "title": "Check the bottom position"
    },
    {
      "text": "Push through your whole feet to stand. Straighten your hips and knees together, keeping your knees aligned with your toes.",
      "title": "Stand back up"
    },
    {
      "text": "Finish tall with your ribs stacked over your hips and feet still planted. Repeat slowly, maintaining the same alignment on every repetition.",
      "title": "Confirm your finishing position"
    }
  ]
}

{
  "steps": [
    {
      "text": "Separe farinha de trigo, fermento biológico seco, água morna, açúcar, sal e óleo ou manteiga. Use uma tigela grande e uma superfície limpa para sovar.",
      "title": "Separe os ingredientes"
    },
    {
      "text": "Coloque a água morna na tigela. Ela deve estar morna ao toque, não quente; se estiver quente demais, espere esfriar para não prejudicar o fermento.",
      "title": "Adicione água morna"
    },
    {
      "text": "Polvilhe o fermento biológico seco sobre a água morna. Espalhe-o pela superfície para que entre em contato com o líquido.",
      "title": "Acrescente o fermento"
    },
    {
      "text": "Adicione o açúcar à tigela. Ele deve se dissolver na água antes de você continuar.",
      "title": "Junte o açúcar"
    },
    {
      "text": "Aguarde cerca de 5 a 10 minutos. A mistura deve formar uma espuma ou bolhas na superfície; isso confirma que o fermento está ativo.",
      "title": "Espere o fermento espumar"
    },
    {
      "text": "Adicione o óleo ou a manteiga à mistura espumosa. Se usar manteiga, ela deve estar derretida e fria ou em temperatura ambiente.",
      "title": "Incorpore a gordura"
    },
    {
      "text": "Acrescente o sal à tigela, evitando despejá-lo diretamente sobre o fermento espumado. A mistura deve continuar líquida e uniforme.",
      "title": "Adicione o sal"
    },
    {
      "text": "Coloque parte da farinha na tigela. Misture com uma colher até não ver farinha seca nessa primeira porção.",
      "title": "Misture a primeira farinha"
    },
    {
      "text": "Acrescente mais farinha aos poucos. Pare de adicionar quando a massa ficar macia, úmida e começar a se soltar das laterais da tigela.",
      "title": "Adicione a farinha aos poucos"
    },
    {
      "text": "Transfira a massa para a superfície limpa levemente enfarinhada. Ela deve formar uma porção única, mesmo que ainda esteja um pouco pegajosa.",
      "title": "Passe a massa à bancada"
    },
    {
      "text": "Empurre a massa para frente com a base da mão. Dobre-a sobre si mesma depois de cada empurrão.",
      "title": "Sove com a base da mão"
    },
    {
      "text": "Gire a massa um quarto de volta. Continue empurrando e dobrando para trabalhar todos os lados por igual.",
      "title": "Gire a massa durante a sova"
    },
    {
      "text": "Sove por cerca de 10 minutos. A massa estará pronta quando ficar lisa, elástica e voltar parcialmente ao ser pressionada com um dedo.",
      "title": "Confirme o ponto da massa"
    }
  ]
}

{
  "steps": [
    {
      "text": "Reúne un destornillador, llave ajustable, pinzas, trapo y el repuesto compatible. Ten a mano una toalla para secar el área; debes poder alcanzar las válvulas bajo el lavabo.",
      "title": "Reúne las herramientas"
    },
    {
      "text": "Gira completamente hacia la derecha las dos válvulas de cierre bajo el lavabo: una de agua fría y otra de caliente. Las manijas del grifo deben quedar sin presión.",
      "title": "Cierra el suministro de agua"
    },
    {
      "text": "Abre el grifo y deja que salga el agua restante. Espera hasta que el flujo se detenga; unas pocas gotas iniciales son normales.",
      "title": "Vacía la presión del grifo"
    },
    {
      "text": "Cubre el desagüe con el tapón o un trapo. Así evitarás que tornillos, clips o piezas pequeñas caigan dentro de la tubería.",
      "title": "Tapa el desagüe"
    },
    {
      "text": "Retira la tapa decorativa de la manija con un destornillador plano o la punta de un cuchillo. Debajo debes ver el tornillo que fija la manija.",
      "title": "Quita la tapa de la manija"
    },
    {
      "text": "Afloja el tornillo de la manija con el destornillador adecuado. Guárdalo en un lugar visible; la manija debe quedar suelta.",
      "title": "Afloja el tornillo de la manija"
    },
    {
      "text": "Jala la manija recto hacia arriba para retirarla. Si está trabada, muévela suavemente de lado a lado sin forzar las tuberías.",
      "title": "Retira la manija"
    },
    {
      "text": "Extrae el cartucho o vástago del cuerpo del grifo. Quita primero la tuerca o clip retenedor con una llave; recuerda su orientación para reinstalarlo igual.",
      "title": "Saca el cartucho o vástago"
    },
    {
      "text": "Examina la pieza extraída y sus sellos de goma. Busca grietas, deformación, sarro o una arandela gastada; esa es la pieza que debes reemplazar.",
      "title": "Identifica la pieza dañada"
    },
    {
      "text": "Lleva la pieza dañada a una ferretería y compra un repuesto idéntico. Compara forma, tamaño y posición de las ranuras antes de regresar a la reparación.",
      "title": "Consigue el repuesto compatible"
    },
    {
      "text": "Inserta el cartucho, vástago o arandela nueva en la misma orientación que la pieza anterior. Debe asentarse completamente sin necesitar golpes.",
      "title": "Instala la pieza nueva"
    },
    {
      "text": "Aprieta la tuerca o reinstala el clip retenedor para fijar la pieza. Ajusta hasta que quede firme, sin excederte ni forzar la rosca.",
      "title": "Fija el repuesto"
    },
    {
      "text": "Coloca la manija sobre el vástago y alinea su posición de apagado. Debe encajar sin holguras antes de asegurarla.",
      "title": "Vuelve a colocar la manija"
    },
    {
      "text": "Aprieta el tornillo de la manija y vuelve a poner la tapa decorativa. La manija debe girar con suavidad y no tambalearse.",
      "title": "Asegura la manija"
    },
    {
      "text": "Abre lentamente las válvulas de cierre bajo el lavabo, girándolas hacia la izquierda. Revisa de inmediato que no aparezcan fugas debajo del grifo.",
      "title": "Restablece el agua"
    },
    {
      "text": "Cierra el grifo y observa el caño durante un minuto. Si no cae ninguna gota y no hay humedad bajo el lavabo, la reparación está terminada.",
      "title": "Comprueba que no gotee"
    }
  ]
}

{
  "steps": [
    {
      "text": "Click **File** in the top-left corner of the application window. You should see a menu with saving options.",
      "title": "Open the File menu"
    },
    {
      "text": "Click **Save**. If the document has already been saved before, your latest changes are stored and you can stop here.",
      "title": "Choose Save"
    },
    {
      "text": "Select the folder where you want to keep the document. The chosen folder should appear as the current save location.",
      "title": "Choose a save location"
    },
    {
      "text": "Click the **File name** field and type a clear name for your document. You should see the new name in the field.",
      "title": "Enter a file name"
    },
    {
      "text": "Click **Save** in the dialog box. Return to your document and confirm its name appears in the title bar without an unsaved-change indicator.",
      "title": "Confirm the save"
    }
  ]
}

{
  "steps": [
    {
      "text": "Place the motherboard on its box or an anti-static mat. Keep the CPU, cooler, RAM, storage, graphics card, case, power supply, and screwdriver within reach.",
      "title": "Prepare a static-safe workspace"
    },
    {
      "text": "Lift the motherboard CPU socket retention arm. Match the CPU’s small gold triangle with the triangle on the socket, then lower the CPU straight in. It should sit flat without force.",
      "title": "Install the CPU"
    },
    {
      "text": "Lower the socket cover and press the retention arm under its hook. The plastic socket cover may pop off; keep it in the motherboard box.",
      "title": "Lock the CPU socket"
    },
    {
      "text": "Apply a pea-sized dot of thermal paste to the CPU center if the cooler does not already have paste. Do not spread it or use extra paste.",
      "title": "Apply thermal paste"
    },
    {
      "text": "Set the CPU cooler onto the CPU, aligning its mounting points. The cooler should rest evenly on the processor before you secure it.",
      "title": "Position the CPU cooler"
    },
    {
      "text": "Tighten the cooler’s screws in an X pattern, a few turns at a time. Stop when snug; do not overtighten. Connect its cable to the `CPU_FAN` header.",
      "title": "Secure the CPU cooler"
    },
    {
      "text": "Open the retaining clips on the recommended RAM slots, usually `A2` and `B2`. Check the motherboard manual if the slot labels are unclear.",
      "title": "Open the RAM slots"
    },
    {
      "text": "Align each RAM stick’s notch with the slot key and press straight down on both ends. The clips should click into place around each module.",
      "title": "Install the RAM"
    },
    {
      "text": "Locate the top M.2 slot and remove its heatsink or retaining screw. Keep the screw nearby; it is small and easy to lose.",
      "title": "Open the M.2 storage slot"
    },
    {
      "text": "Slide the M.2 SSD into its slot at a slight angle. Push it down flat and secure it with the screw or heatsink. It should not move after fastening.",
      "title": "Install the M.2 SSD"
    },
    {
      "text": "Install the case’s motherboard standoffs only where they match your board’s mounting holes. Confirm no extra standoff sits beneath the motherboard.",
      "title": "Check case standoff positions"
    },
    {
      "text": "Lower the motherboard into the case, aligning its rear ports with the I/O opening and its holes with the standoffs. It should lie flat without bending.",
      "title": "Place the motherboard in the case"
    },
    {
      "text": "Fasten the motherboard screws into all accessible standoffs. Tighten until snug, then stop; the board should be secure and not flex.",
      "title": "Secure the motherboard"
    },
    {
      "text": "Slide the power supply into its case bay with its fan facing the case ventilation. Attach it using the four screws supplied with the case or PSU.",
      "title": "Mount the power supply"
    },
    {
      "text": "Plug the 24-pin motherboard cable into the board’s large `ATX` power connector. Press until the latch clicks over the connector tab.",
      "title": "Connect 24-pin motherboard power"
    },
    {
      "text": "Plug the 8-pin CPU power cable into the `CPU_PWR` or `EPS` connector near the top of the motherboard. Ensure the latch locks in place.",
      "title": "Connect CPU power"
    },
    {
      "text": "Remove the rear expansion-slot covers aligned with the top full-length PCIe slot. Keep their screws for securing the graphics card.",
      "title": "Open the GPU expansion slots"
    },
    {
      "text": "Align the graphics card with the top PCIe x16 slot and press straight down until the slot latch clicks. Its rear bracket should sit flush with the case.",
      "title": "Install the graphics card"
    },
    {
      "text": "Fasten the graphics card bracket to the case using the saved expansion-slot screws. The card should not sag or shift at its rear edge.",
      "title": "Secure the graphics card"
